// v2 - Gestion améliorée du mode hors ligne pour éviter la déconnexion
import { createClient } from '@supabase/supabase-js';
import type { Database } from './types';
import { shouldAssumeOffline } from '@/lib/networkHealth';
import { resolveBackendUrl } from '@/config/backend';

// Configuration Supabase - variables d'environnement Vercel avec fallback hardcodé
// Une fois VITE_SUPABASE_URL et VITE_SUPABASE_ANON_KEY configurés sur Vercel,
// les fallbacks ne seront plus utilisés.
const SUPABASE_URL = import.meta.env.NEXT_PUBLIC_VITE_SUPABASE_URL || import.meta.env.VITE_SUPABASE_URL || "";
const SUPABASE_KEY = import.meta.env.NEXT_PUBLIC_VITE_SUPABASE_ANON_KEY || import.meta.env.VITE_SUPABASE_ANON_KEY || "";

if (!SUPABASE_URL || !SUPABASE_KEY) {
  console.error('❌ [CRITICAL] Supabase URL or Key missing. Set VITE_SUPABASE_URL and VITE_SUPABASE_ANON_KEY.');
}

// Import the supabase client like this:
// import { supabase } from "@/integrations/supabase/client";

export const supabase = createClient<Database>(SUPABASE_URL, SUPABASE_KEY, {
  auth: {
    storage: localStorage,
    persistSession: true,
    autoRefreshToken: true,
    detectSessionInUrl: true,
    flowType: 'pkce',
  },
  global: {
    headers: {
      'X-Client-Info': '224solutions-web',
    },
    fetch: (url, options = {}) => {
      // Enable keepalive for all requests to reuse TCP connections
      return fetch(url, { ...options, keepalive: true });
    },
  },
  db: {
    schema: 'public',
  },
  realtime: {
    params: {
      eventsPerSecond: 10,
    },
  },
});

const NODE_BACKEND_EDGE_EXACT = new Set([
  'vendor-ai-assistant',
  'pdg-ai-assistant',
  'ai-copilot',
  'ai-error-analyzer',
  'visual-search',
  'delivery-payment',
  'send-delivery-notification',
  'send-otp-email',
  'send-sms',
  'send-security-alert',
  'geo-detect',
  'geocode-address',
  'google-places-autocomplete',
  'gcs-signed-url',
  'marketplace-escrow-payment',
  'stripe-marketplace-payment',
  'link-escrow-order',
  'confirm-stripe-deposit',
]);

const NODE_BACKEND_EDGE_PREFIXES = [
  'chapchappay-',
  'paypal-',
  'stripe-',
  'escrow-',
  'security-',
];

const NODE_BACKEND_EDGE_AI_NESTED = new Set([
  'vendor-ai-assistant',
  'pdg-ai-assistant',
  'ai-copilot',
]);

const NODE_BACKEND_EDGE_ORDER_FUNCTIONS = new Set([
  'marketplace-escrow-payment',
  'stripe-marketplace-payment',
  'link-escrow-order',
]);

const NODE_BACKEND_EDGE_PAYMENT_FUNCTIONS = new Set([
  'confirm-stripe-deposit',
]);

function shouldRouteFunctionThroughNode(functionName: string): boolean {
  return NODE_BACKEND_EDGE_EXACT.has(functionName)
    || NODE_BACKEND_EDGE_PREFIXES.some((prefix) => functionName.startsWith(prefix));
}

function getNodeEdgeFunctionCandidates(functionName: string): string[] {
  if (NODE_BACKEND_EDGE_AI_NESTED.has(functionName)) {
    return [`/edge-functions/ai/${functionName}`, `/edge-functions/${functionName}`];
  }

  if (NODE_BACKEND_EDGE_ORDER_FUNCTIONS.has(functionName)) {
    return [`/edge-functions/orders/${functionName}`, `/edge-functions/${functionName}`];
  }

  if (NODE_BACKEND_EDGE_PAYMENT_FUNCTIONS.has(functionName)) {
    return [`/edge-functions/payments/${functionName}`, `/edge-functions/${functionName}`];
  }

  if (
    functionName.startsWith('chapchappay-')
    || functionName.startsWith('paypal-')
    || functionName.startsWith('stripe-')
    || functionName.startsWith('escrow-')
  ) {
    return [`/edge-functions/payments/${functionName}`, `/edge-functions/${functionName}`];
  }

  return [`/edge-functions/${functionName}`];
}

async function invokeNodeEdgeFunction(functionName: string, options: Record<string, any> = {}) {
  const { data: sessionData } = await supabase.auth.getSession();
  const token = sessionData.session?.access_token;
  const method = String(options.method || 'POST').toUpperCase();
  const headers = new Headers(options.headers || {});

  if (token && !headers.has('Authorization')) {
    headers.set('Authorization', `Bearer ${token}`);
  }

  const isFormData = typeof FormData !== 'undefined' && options.body instanceof FormData;
  let body: BodyInit | undefined;

  if (!(method === 'GET' && options.body && typeof options.body === 'object' && !isFormData) && options.body !== undefined) {
    if (isFormData) {
      body = options.body as FormData;
    } else if (typeof options.body === 'string') {
      body = options.body;
      if (!headers.has('Content-Type')) {
        headers.set('Content-Type', 'application/json');
      }
    } else {
      body = JSON.stringify(options.body);
      if (!headers.has('Content-Type')) {
        headers.set('Content-Type', 'application/json');
      }
    }
  }

  try {
    const candidates = getNodeEdgeFunctionCandidates(functionName);

    for (let index = 0; index < candidates.length; index++) {
      let url = candidates[index];

      if (method === 'GET' && options.body && typeof options.body === 'object' && !isFormData) {
        const params = new URLSearchParams();
        for (const [key, value] of Object.entries(options.body)) {
          if (value !== undefined && value !== null) {
            params.set(key, String(value));
          }
        }
        const query = params.toString();
        if (query) {
          url += `?${query}`;
        }
      }

      const response = await fetch(resolveBackendUrl(url), {
        method,
        headers,
        body,
        keepalive: true,
      });

      if (response.status === 404 && index < candidates.length - 1) {
        continue;
      }

      const contentType = response.headers.get('content-type') || '';
      const payload = contentType.includes('application/json')
        ? await response.json()
        : await response.text();

      if (!response.ok) {
        return {
          data: null,
          error: {
            message: (typeof payload === 'object' && payload && 'error' in payload)
              ? String((payload as { error?: unknown }).error || `Erreur ${response.status}`)
              : (typeof payload === 'string' && payload) || `Erreur ${response.status}`,
            status: response.status,
            details: payload,
          },
        };
      }

      return { data: payload, error: null };
    }

    return {
      data: null,
      error: {
        message: `Route backend introuvable pour ${functionName}`,
      },
    };
  } catch (error: any) {
    return {
      data: null,
      error: {
        message: error?.message || 'Erreur réseau backend',
      },
    };
  }
}

const originalInvoke = supabase.functions.invoke.bind(supabase.functions);
(supabase.functions as any).invoke = async (functionName: string, options: Record<string, any> = {}) => {
  if (shouldRouteFunctionThroughNode(functionName)) {
    return invokeNodeEdgeFunction(functionName, options);
  }

  return originalInvoke(functionName, options);
};

/**
 * Vérifie si l'app est en mode hors ligne
 */
export const isOffline = (): boolean => {
  return shouldAssumeOffline();
};

/**
 * Fonction pour rafraîchir manuellement la session si elle expire
 * NE PAS rafraîchir si offline pour éviter la déconnexion
 */
export const refreshSession = async () => {
  // Ne pas essayer de rafraîchir si offline
  if (isOffline()) {
    console.log('⏸️ [Supabase] Rafraîchissement ignoré - mode hors ligne');
    return null;
  }

  try {
    const { data, error } = await supabase.auth.refreshSession();
    if (error) {
      // Ignorer les erreurs réseau en mode offline
      if (error.message?.includes('network') || error.message?.includes('fetch')) {
        console.warn('⚠️ [Supabase] Erreur réseau ignorée (probablement offline)');
        return null;
      }
      console.error('❌ Erreur rafraîchissement session:', error);
      return null;
    }
    console.log('✅ Session rafraîchie avec succès');
    return data.session;
  } catch (e: any) {
    // Ignorer les erreurs réseau
    if (e?.message?.includes('network') || e?.message?.includes('fetch') || e?.message?.includes('Failed to fetch')) {
      console.warn('⚠️ [Supabase] Exception réseau ignorée (probablement offline)');
      return null;
    }
    console.error('❌ Exception rafraîchissement session:', e);
    return null;
  }
};

// Vérification périodique de la session (toutes les 5 minutes) - seulement si online
let sessionCheckInterval: ReturnType<typeof setInterval> | null = null;

export const startSessionMonitor = () => {
  if (sessionCheckInterval) return;

  sessionCheckInterval = setInterval(async () => {
    // Ne pas vérifier la session si offline pour éviter erreurs et déconnexion
    if (isOffline()) {
      console.log('⏸️ [Supabase] Vérification session ignorée - mode hors ligne');
      return;
    }

    try {
      const { data: { session }, error } = await supabase.auth.getSession();

      // Ignorer les erreurs réseau
      if (error) {
        if (error.message?.includes('network') || error.message?.includes('fetch')) {
          return;
        }
        console.warn('⚠️ [Supabase] Erreur getSession:', error.message);
        return;
      }

      if (session) {
        // Vérifier si le token expire dans moins de 10 minutes
        const expiresAt = session.expires_at || 0;
        const now = Math.floor(Date.now() / 1000);
        const timeUntilExpiry = expiresAt - now;

        if (timeUntilExpiry < 600 && timeUntilExpiry > 0) {
          console.log('⚠️ Session expire bientôt, rafraîchissement...');
          await refreshSession();
        }
      }
    } catch (e: any) {
      // Ignorer silencieusement les erreurs réseau
      if (e?.message?.includes('network') || e?.message?.includes('fetch') || e?.message?.includes('Failed to fetch')) {
        return;
      }
      console.warn('⚠️ [Supabase] Exception monitor:', e?.message);
    }
  }, 5 * 60 * 1000); // Toutes les 5 minutes
};

export const stopSessionMonitor = () => {
  if (sessionCheckInterval) {
    clearInterval(sessionCheckInterval);
    sessionCheckInterval = null;
  }
};

/**
 * Récupère la session locale sans faire d'appel réseau
 * Utile pour le mode offline
 */
export const getLocalSession = () => {
  try {
    const candidates = new Set<string>();

    const refFromAnon = (() => {
      try {
        const token = SUPABASE_KEY;
        const parts = token.split('.');
        if (parts.length < 2) return null;
        const payload = JSON.parse(atob(parts[1]));
        return typeof payload?.ref === 'string' ? payload.ref : null;
      } catch {
        return null;
      }
    })();

    if (refFromAnon) {
      candidates.add(`sb-${refFromAnon}-auth-token`);
    }

    if (SUPABASE_URL) {
      try {
        const hostPrefix = new URL(SUPABASE_URL).hostname.split('.')[0];
        if (hostPrefix) {
          candidates.add(`sb-${hostPrefix}-auth-token`);
        }
      } catch {
        // Ignore malformed URL silently.
      }
    }

    for (const storageKey of candidates) {
      const stored = localStorage.getItem(storageKey);
      if (stored) {
        const parsed = JSON.parse(stored);
        return parsed;
      }
    }
  } catch (e) {
    console.warn('⚠️ [Supabase] Erreur lecture session locale:', e);
  }
  return null;
};
